DELETE FROM public.scraped_jobs WHERE lower(title) LIKE 'venture capital jobs in%' OR lower(title) LIKE 'venture capital careers%' OR lower(title) IN ('filters and topics', 'search results', 'united states', 'the vc industry''s trusted resource') OR (company = 'Unknown' AND length(title) < 15) OR (lower(description) LIKE '%subscribing to our%' AND lower(description) LIKE '%newsletter%');